import React, { useState, useEffect, useContext} from "react";
import { AppBar, Toolbar, IconButton, Typography, Button, Drawer, List, ListItem, ListItemText, useMediaQuery, CssBaseline, Menu, MenuItem, Box, Container } from "@mui/material";
import MenuIcon from "@mui/icons-material/Menu";
import GitHubIcon from "@mui/icons-material/GitHub";
import Brightness4Icon from "@mui/icons-material/Brightness4";

import DarkModeIcon from '@mui/icons-material/DarkModeRounded';
import LightModeIcon from '@mui/icons-material/LightModeRounded';
import Projects from "../projects/Projects";
import About from "../../about/About";
import Intro from "../intro/Intro";
import Skills from "../skills/Skills";
import Experience from "../exprience/Exprience";
import Contact from "../contacts/Contacts";
import { ThemeContext } from "../../utils/switchTheme";


const sections = [
  { title: "About", url: "#about" },
  { title: "Skills", url: "#skills" },
  { title: "Experience", url: "#experience" },
  { title: "Projects", url: "#projects" },
  { title: "Education", url: "#education" },
  { title: "Contact", url: "#contact" }
];

const Dashboard = () => {
  const [drawerOpen, setDrawerOpen] = useState(false);
  const [anchorEl, setAnchorEl] = useState(null);
  const [mode, setMode] = useState("system"); // state for theme mode (light, dark, or system)
  const { theme, setTheme } = useContext(ThemeContext);

  const isMobile = window.innerWidth <= 768;
  const prefersDarkMode = useMediaQuery("(prefers-color-scheme: dark)");


  const toggleTheme = (newTheme) => {
    setTheme(newTheme);
  };



  const handleDrawerToggle = () => {
    setDrawerOpen(!drawerOpen);
  };

  const handleMenuClick = (event) => {
    setAnchorEl(event.currentTarget);
  };

  const handleMenuClose = () => {
    setAnchorEl(null);
  };

  // Create theme based on selected mode

  // Conditionally change the icon in the menu based on the selected mode
  const themeIcon = theme === "dark" ? (
    <DarkModeIcon />
  ) : theme === "light" ? (
    <LightModeIcon />
  ) : (
    <Brightness4Icon />
  );

  return (
      <div style={{ 
  margin: "0 auto",
  // padding: "0 20px",
  position: "relative",
  overflow: "hidden",}}>
      <CssBaseline />

<AppBar position="fixed" sx={{ width: '100%', zIndex: 1201,padding: "20px 0",
    borderBottom:" 1px solid var(--border)",background:"transparent" }}>
        <Toolbar sx={{ display: "flex", justifyContent: "space-between", alignItems: "center" }}>
          {/* Mobile Menu Icon */}
          <div style={{ display: isMobile ? "block" : "none" }}>
            <IconButton edge="start" color="inherit" onClick={handleDrawerToggle}>
              <MenuIcon />
            </IconButton>
          </div>

          {/* Portfolio Title */}
          <Typography variant="h6" sx={{ textAlign: isMobile ? "center" : "left" }}>
            My Portfolio
          </Typography>

          {/* GitHub Icon for Mobile */}
          {isMobile && (
            <IconButton color="inherit" href="https://github.com" target="_blank">
              <GitHubIcon />
            </IconButton>
          )}

          {/* Desktop Items */}
          {!isMobile && (
            <Box sx={{ display: "flex", alignItems: "center", gap: 1 }}>
              {/* Sections */}
              <div>
                {sections.map((section) => (
                  <Button key={section.title} color="inherit" href={section.url}>
                    {section.title}
                  </Button>
                ))}
              </div>
            </Box>
          )}

          {/* Desktop Icons */}
          {!isMobile && (
            <Box sx={{ display: "flex", alignItems: "center", gap: 1 }}>
              <IconButton color="inherit" onClick={handleMenuClick}>
                {themeIcon}
              </IconButton>
              <Menu anchorEl={anchorEl} open={Boolean(anchorEl)} onClose={handleMenuClose}>
                <MenuItem onClick={() => { toggleTheme("light"); handleMenuClose(); }}>
                  <LightModeIcon sx={{ marginRight: 1 }} />
                  Light
                </MenuItem>
                <MenuItem onClick={() => { toggleTheme("dark"); handleMenuClose(); }}>
                  <DarkModeIcon sx={{ marginRight: 1 }} />
                  Dark
                </MenuItem>
                <MenuItem onClick={() => { toggleTheme("system"); handleMenuClose(); }}>
                  <Brightness4Icon sx={{ marginRight: 1 }} />
                  System
                </MenuItem>
              </Menu>
              <IconButton color="inherit" href="https://github.com" target="_blank">
                <GitHubIcon />
              </IconButton>
            </Box>
          )}
        </Toolbar>
      </AppBar>


      {/* Drawer for Mobile View */}
      <Drawer anchor="left" open={drawerOpen} onClose={handleDrawerToggle}>
        <Box sx={{ width: 250, padding: 2 }}>
          {/* Drawer Title */}
          <Typography variant="h6" sx={{ marginBottom: 2 }}>
            My Portfolio
          </Typography>

          {/* Menu Items */}
          <List>
            {sections.map((section) => (
              <ListItem button key={section.title} onClick={handleDrawerToggle} component="a" href={section.url}>
                <ListItemText primary={section.title} />
              </ListItem>
            ))}
          </List>

          {/* Dark/Light Mode Toggle */}
          <Box sx={{ display: "flex", alignItems: "center", marginTop: 2 }}>
            <Typography variant="body2" sx={{ marginRight: 1 }}>
              Theme:
            </Typography>
            <IconButton
              color="inherit"
              onClick={() => setMode(mode === "dark" ? "light" : "dark")}
            >
              {mode === "dark" ? <LightModeIcon /> : <DarkModeIcon />}
            </IconButton>
          </Box>
        </Box>
      </Drawer>

      {/* Content below navbar */}
      <Box sx={{ marginTop: "84px" }}>
        <Box id="about" >

          <Intro />
        </Box>
        <Box id="skills" sx={{ padding: 4 }}>

          <Skills />
        </Box>
        <Box id="experience" sx={{ padding: 4 }}>
       <Experience />
        </Box>
        <Box id="projects" sx={{ padding: 2 }}>

          <Projects />
        </Box>
        <Box id="projects" sx={{ padding: 2 }}>

<About />
</Box>

        <Box id="contact" sx={{ padding: 4 }}>
          <Contact />
        </Box>
      </Box>
      </div>
  );
};

export default Dashboard;
